const now = new Date();
const since = new Date(now.getTime() - 60 * 60 * 1000);
const owner = $json.owner;
const repo = $json.repo;
return [{
  json: {
    owner,
    repo,
    team_id: repo,
    repo_name: `${owner}/${repo}`,
    since: since.toISOString(),
    until: now.toISOString()
  }
}];

const ctx = $('ComputeHourWindow').first().json;
const token = $env.GITHUB_PAT || $env.GITHUB_TOKEN || '';
let list = $('Get repo commit').all().map(i => i.json);
if (list.length === 1 && Array.isArray(list[0])) list = list[0];
else if (list.length === 1 && list[0]?.sha && !list[0]?.files) list = [list[0]];
list = list.filter(c => c && c.sha);
if (!list.length) return [];
const details = [];
for (const c of list) {
  const sha = c.sha;
  try {
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://api.github.com/repos/${ctx.owner}/${ctx.repo}/commits/${sha}`,
      headers: {
        Authorization: `Bearer ${token}`,
        Accept: 'application/vnd.github+json',
        'User-Agent': 'n8n-ai-review'
      },
      json: true
    });
    details.push(res);
  } catch (e) {
    details.push({ sha, commit: c.commit || {}, files: [], error: String(e.message || e) });
  }
}
return [{ json: { ctx, details } }];

const IGNORED = new Set(['.gitignore','package-lock.json','yarn.lock','.env','README.md']);
const CONFIG_NAMES = new Set(['requirements.txt','requirements-dev.txt','pyproject.toml','poetry.lock','pipfile','package.json','docker-compose.yml','docker-compose.yaml','dockerfile','makefile','cargo.toml','go.mod','.env.example','application.yml','application.yaml','application.properties','tsconfig.json','vite.config.ts','vite.config.js']);
const PATCH_LIMIT = 3000;
const TOTAL_LIMIT = 50000;

function shouldInclude(filename) {
  if (!filename) return false;
  const n = filename.trim();
  if (IGNORED.has(n)) return false;
  return !n.toLowerCase().endsWith('.lock');
}
function isConfig(filename) {
  const base = filename.includes('/') ? filename.slice(filename.lastIndexOf('/') + 1) : filename;
  const lower = base.toLowerCase();
  if (CONFIG_NAMES.has(lower)) return true;
  return lower.endsWith('.env.example') || lower.endsWith('.yaml') || lower.endsWith('.yml') || lower.endsWith('.toml') || lower.startsWith('dockerfile');
}
function trim(value, max) {
  if (!value) return '';
  const t = String(value).trim().replace(/\n/g, ' ');
  return t.length <= max ? t : t.slice(0, max) + '…';
}
function toUtc7(iso) {
  if (!iso) return new Date().toISOString();
  const d = new Date(iso);
  return new Date(d.getTime() + 7 * 3600000).toISOString().replace('Z', '+07:00');
}

const pack = $json;
const ctx = pack.ctx || $('ComputeHourWindow').first().json;
const details = pack.details || [];
if (!details.length) return [];

const modifiedSet = new Set();
const configSet = new Set();
let activityLog = '';
let codeDetail = '';
const firebaseRecords = [];

for (const commit of details) {
  const sha = commit.sha || '';
  const shortSha = sha.slice(0, 7);
  const msg = commit.commit?.message || '';
  const committedAt = commit.commit?.author?.date || commit.commit?.committer?.date || '';
  const files = (commit.files || []).filter(f => shouldInclude(f.filename));
  files.forEach(f => {
    modifiedSet.add(f.filename.trim());
    if (isConfig(f.filename)) configSet.add(f.filename.trim());
  });
  const fileNames = files.map(f => f.filename).join(', ') || '(no files)';
  if (activityLog) activityLog += '\n';
  activityLog += `${shortSha}: ${trim(msg, 200)} | ${fileNames}`;

  let diffContent = '';
  for (const file of files) {
    diffContent += `\n--- ${file.filename} (+${file.additions || 0}/-${file.deletions || 0}) ---\n`;
    let patch = file.patch || '';
    if (patch.length > PATCH_LIMIT) patch = patch.slice(0, PATCH_LIMIT) + '\n... [Truncated] ...';
    diffContent += patch;
  }

  firebaseRecords.push({
    commit_sha: sha,
    repo_name: ctx.repo_name,
    team_id: ctx.team_id,
    author: commit.commit?.author?.name || commit.author?.login || 'unknown',
    timestamp: toUtc7(committedAt),
    commit_message: trim(msg, 500),
    branch: 'main',
    stats: {
      additions: commit.stats?.additions || 0,
      deletions: commit.stats?.deletions || 0,
      files_changed_count: files.length
    },
    modified_files_list: files.map(f => f.filename),
    config_files_detected: files.filter(f => isConfig(f.filename)).map(f => f.filename)
  });

  if (codeDetail) codeDetail += '\n=== COMMIT-BOUNDARY ===\n';
  codeDetail += `SHA: ${sha}\nMessage: ${trim(msg, 500)}\n`;
  codeDetail += diffContent;
  if (codeDetail.length >= TOTAL_LIMIT) {
    codeDetail = codeDetail.slice(0, TOTAL_LIMIT) + '\n... [Truncated total diff] ...';
    break;
  }
}

if (codeDetail.length > TOTAL_LIMIT) {
  codeDetail = codeDetail.slice(0, TOTAL_LIMIT) + '\n... [Truncated total diff] ...';
}

const modifiedList = [...modifiedSet];
const configList = [...configSet];

return [{
  json: {
    repo_name: ctx.repo_name,
    team_id: ctx.team_id,
    owner: ctx.owner,
    repo: ctx.repo,
    commit_sha: details[0].sha,
    commit_count: details.length,
    activity_log: activityLog,
    code_changes_detail: codeDetail || '(no diff)',
    modified_files_list: modifiedList,
    config_files_detected: configList,
    cron_batch_review: true,
    batched_commit_shas: details.map(c => c.sha),
    timestamp: new Date().toISOString(),
    firebase_records: firebaseRecords,
    firebase_base: ($env.N8N_FIREBASE_DATABASE_URL || '').replace(/\/$/, '')
  }
}];

const batch = $json;
const base = batch.firebase_base;
const token = $env.N8N_FIREBASE_ACCESS_TOKEN || '';
if (!base || !token || !(batch.firebase_records || []).length) {
  return [{ json: { skipped: true, reason: 'firebase not configured or no commits' } }];
}
for (const rec of batch.firebase_records) {
  try {
    await this.helpers.httpRequest({
      method: 'PUT',
      url: `${base}/commit/${rec.commit_sha}.json`,
      headers: {
        Authorization: `Bearer ${token}`,
        'Content-Type': 'application/json'
      },
      body: rec,
      json: true
    });
  } catch (e) {
    // continue other commits
  }
}
return [{ json: { firebase_written: (batch.firebase_records || []).length } }];

const s = $('Summation').first().json;
return [{
  json: {
    repo_name: s.repo_name,
    team_id: s.team_id,
    owner: s.owner,
    repo: s.repo,
    commit_sha: s.commit_sha,
    commit_count: s.commit_count,
    activity_log: s.activity_log,
    code_changes_detail: s.code_changes_detail,
    modified_files_list: s.modified_files_list,
    config_files_detected: s.config_files_detected,
    cron_batch_review: true,
    batched_commit_shas: s.batched_commit_shas,
    timestamp: s.timestamp
  }
}];
